const body = $json.body || {};
const dossierId = $json.dossier_id || body.dossier_id || 'DOSSIER-UNSPECIFIED';
const routeId = $json.route_id || body.route_id || 'ROUTE_PHASE1_STANDARD';
const decision = $json.approval_decision || body.approval_decision || $json.approval_status || body.approval_status || 'APPROVED';
const replayTarget = $json.replay_target_workflow || body.replay_target_workflow || 'CWF-210';
return [{ json: { ...$json, dossier_id: dossierId, route_id: routeId, approval_decision: decision, replay_target_workflow: replayTarget, dossier_context: { dossier_id: dossierId, loaded_at: new Date().toISOString() } } }];

const now = new Date().toISOString();
const dossierId = $json.dossier_id || 'DOSSIER-UNSPECIFIED';
const routeId = $json.route_id || 'WF-020-ROUTE';
const researchConfidence = Number($json.research_confidence_score ?? 0.90);
const approvalDecision = $json.approval_decision || 'APPROVED';
const packet = {
  instance_id: 'WF-020-' + Date.now(),
  artifact_family: 'approval_decision_packet',
  schema_version: '1.0.0',
  producer_workflow: 'WF-020',
  dossier_ref: dossierId,
  created_at: now,
  status: 'CREATED',
  payload: {
    workflow_id: 'WF-020',
    route_id: routeId,
    research_confidence_score: researchConfidence,
    approval_decision: approvalDecision
  }
};
return [{ json: { ...$json, runtime_packet: packet, runtime: { had_error: false, error_message: '' } } }];

try {
  const packet = $json.runtime_packet;
  if (!packet || !packet.instance_id || !packet.artifact_family || !packet.dossier_ref) {
    throw new Error('missing required runtime_packet fields');
  }
  return [{ json: { ...$json, validation_status: 'SUCCESS', route_to_error: false } }];
} catch (error) {
  return [{ json: { ...$json, validation_status: 'FAILED', route_to_error: true, validation_error: String(error.message || error) } }];
}

if ($json.route_to_error) return [];
const fs = require('fs');
const path = require('path');

const now = new Date().toISOString();
const packet = $json.runtime_packet || {};
const dossierId = packet.dossier_ref || $json.dossier_id || 'DOSSIER-UNSPECIFIED';
const approvalDecision = (packet.payload && packet.payload.approval_decision) || $json.approval_decision || 'APPROVED';

const repoRoot = 'C:/ShadowEmpire-Git';
const dossiersDir = path.join(repoRoot, 'dossiers');
const dataDir = path.join(repoRoot, 'data');
const dossierPath = path.join(dossiersDir, dossierId + '.json');
const indexPath = path.join(dataDir, 'se_dossier_index.json');

if (!fs.existsSync(dossiersDir)) fs.mkdirSync(dossiersDir, { recursive: true });
if (!fs.existsSync(dataDir)) fs.mkdirSync(dataDir, { recursive: true });

let dossier = {
  dossier_id: dossierId,
  created_at: now,
  status: 'active',
  namespaces: {},
  _version: 0,
  _created_at: now,
  _audit_trail: []
};
if (fs.existsSync(dossierPath)) {
  try {
    const parsed = JSON.parse(fs.readFileSync(dossierPath, 'utf8'));
    dossier = {
      ...dossier,
      ...parsed,
      namespaces: typeof parsed.namespaces === 'object' && parsed.namespaces ? parsed.namespaces : {},
      _audit_trail: Array.isArray(parsed._audit_trail) ? parsed._audit_trail : []
    };
  } catch (e) {
    throw new Error('WF-020 persistence failed: dossier parse error: ' + e.message);
  }
}

const approvalNs = (dossier.namespaces.approval && typeof dossier.namespaces.approval === 'object') ? dossier.namespaces.approval : {};
const decisions = Array.isArray(approvalNs.decisions) ? approvalNs.decisions : [];
decisions.push({
  timestamp: now,
  workflow_id: 'WF-020',
  packet_id: packet.instance_id || null,
  decision: approvalDecision,
  route_next: ($json.routing_decision && $json.routing_decision.on_success_next_workflow) || null
});
approvalNs.decisions = decisions;
approvalNs.latest_decision = approvalDecision;
approvalNs.last_decision_at = now;
dossier.namespaces.approval = approvalNs;
dossier.last_updated = now;
dossier.status = approvalDecision === 'APPROVED' ? 'APPROVED' : 'REJECTED';
dossier._version = Number(dossier._version || 0) + 1;
dossier._last_updated_at = now;
dossier._audit_trail.push({
  timestamp: now,
  workflow_id: 'WF-020',
  operation: 'APPROVAL_DECISION_APPEND',
  decision: approvalDecision,
  notes: 'append approval decision into dossier namespace'
});

fs.writeFileSync(dossierPath, JSON.stringify(dossier, null, 2), 'utf8');

let index = {
  table: 'se_dossier_index',
  description: 'Index of all dossiers; updated by WF-001 and dossier_writer.',
  records: [],
  created_at: now,
  last_updated: now
};
if (fs.existsSync(indexPath)) {
  index = JSON.parse(fs.readFileSync(indexPath, 'utf8'));
  index.records = Array.isArray(index.records) ? index.records : [];
} else {
  index.records = [];
}
const existing = index.records.find((r) => r && r.dossier_id === dossierId);
if (existing) {
  existing.updated_at = now;
  existing.status = dossier.status.toLowerCase();
  existing.source_workflow = 'WF-020 Final Approval Canonical';
} else {
  index.records.push({
    dossier_id: dossierId,
    status: dossier.status.toLowerCase(),
    created_at: now,
    updated_at: now,
    source_workflow: 'WF-020 Final Approval Canonical'
  });
}
index.last_updated = now;
fs.writeFileSync(indexPath, JSON.stringify(index, null, 2), 'utf8');

return [{
  json: {
    ...$json,
    persistence: {
      wf: 'WF-020',
      dossier_path: dossierPath,
      dossier_index_path: indexPath,
      decision: approvalDecision,
      dossier_version: dossier._version,
      persisted_at: now
    },
    dossier_write: {
      mutation_type: 'append_to_array',
      target: 'dossier.runtime_packets',
      timestamp: now,
      writer_id: 'WF-020',
      skill_id: 'WF-020',
      instance_id: packet.instance_id || ('WF-020-' + Date.now()),
      schema_version: packet.schema_version || '1.0.0',
      lineage_reference: packet.producer_workflow || 'WF-020',
      audit_entry: 'append-only dossier write from canonical workflow'
    }
  }
}];

if ($json.route_to_error) return [];
return [{
  json: {
    ...$json,
    se_packet_index_write: {
      operation: 'create_new_index_row',
      packet_id: $json.runtime_packet.instance_id,
      dossier_id: $json.runtime_packet.dossier_ref,
      packet_family: $json.runtime_packet.artifact_family,
      workflow_id: 'WF-020',
      created_at: new Date().toISOString()
    }
  }
}];

if (!$json.route_to_error) return [];
return [{
  json: {
    workflow_id: 'WF-020',
    routing_decision: 'ERROR',
    route_to_workflow: 'WF-900',
    error_message: $json.validation_error || $json.runtime?.error_message || 'unknown workflow error',
    failure_packet: $json.runtime_packet || null
  }
}];

if ($json.route_to_error) return [];
let nextWorkflow = 'WF-300';
let decision = 'SUCCESS_PATH';

if ('WF-020' === 'CWF-140') {
  const confidence = Number($json.runtime_packet?.payload?.research_confidence_score ?? 1);
  if (confidence < 0.85) {
    nextWorkflow = 'CWF-140';
    decision = 'RUN_PHASE1C_CONDITIONAL_RESEARCH';
  } else {
    nextWorkflow = 'CWF-210';
    decision = 'SKIP_PHASE1C_PROCEED_SCRIPT';
  }
}

if ('WF-020' === 'WF-020') {
  const approval = String($json.runtime_packet?.payload?.approval_decision || 'APPROVED');
  nextWorkflow = approval === 'APPROVED' ? 'WF-300' : 'WF-021';
  decision = approval === 'APPROVED' ? 'APPROVED_FOR_PUBLISHING' : 'REJECTED_ROUTE_REPLAY';
}

if ('WF-020' === 'WF-021') {
  nextWorkflow = $json.replay_target_workflow || 'CWF-210';
  decision = 'REPLAY_TO_PRIOR_STAGE';
}

return [{
  json: {
    ...$json,
    routing_decision: {
      on_success_next_workflow: nextWorkflow,
      on_error_workflow: 'WF-900',
      decision,
      wf900_bound: true
    }
  }
}];

if ($json.route_to_error) return [];
const approvalDecision = $json.runtime_packet?.payload?.approval_decision || $json.approval_decision || 'APPROVED';
return [{
  json: {
    workflow_id: 'WF-020',
    execution_status: 'SUCCESS',
    approval_decision: approvalDecision,
    replay_target_workflow: $json.replay_target_workflow || 'CWF-210',
    runtime_packet: $json.runtime_packet,
    routing_decision: $json.routing_decision,
    completion_packet: {
      instance_id: 'WF-020-COMP-' + Date.now(),
      artifact_family: 'workflow_completion_packet',
      schema_version: '1.0.0',
      producer_workflow: 'WF-020',
      dossier_ref: $json.runtime_packet?.dossier_ref || 'DOSSIER-UNSPECIFIED',
      created_at: new Date().toISOString(),
      status: 'CREATED',
      payload: {
        source_packet_id: $json.runtime_packet?.instance_id || null,
        next_workflow: $json.routing_decision?.on_success_next_workflow || 'WF-300',
        route_to_wf900: 'WF-900',
        approval_decision: approvalDecision
      }
    }
  }
}];

// Normalize approval route to single-output data for deterministic branching
const raw = (
  $json.approval_status ||
  $json.approval_decision ||
  ($json.payload && $json.payload.approval_status) ||
  ($json.completion_packet && $json.completion_packet.payload && $json.completion_packet.payload.approval_decision) ||
  ($json.runtime_packet && $json.runtime_packet.payload && $json.runtime_packet.payload.approval_decision) ||
  'approved'
);
const status = String(raw).toLowerCase();
const approved = ['approved','approve','pass','default_approved'].includes(status);
return [{ json: { ...$json, approval_status_normalized: approved ? 'approved' : 'rejected', branch: approved ? 'approved' : 'rejected' } }];

const packet = $json.runtime_packet || {};
const decision = String(packet.payload?.approval_decision || $json.approval_decision || 'APPROVED').toUpperCase();
const allowed = ['APPROVED','REJECTED','REVIEW','REQUIRES_REVIEW'];
const invalid = !packet.instance_id || !packet.dossier_ref || !allowed.includes(decision);
return [{
  json: {
    ...$json,
    parent_status_closure: {
      workflow_id: 'WF-020',
      closure_status: invalid ? 'FAILED' : 'SUCCESS',
      checked_at: new Date().toISOString(),
      approval_decision: decision,
      reason: invalid ? 'Invalid approval packet/decision' : 'Approval closure healthy'
    },
    route_to_error: invalid,
    validation_error: invalid ? 'WF-020 closure validation failed' : null
  }
}];
